<?php declare(strict_types=1); namespace Tests\Feature\Electronics; use App\Domains\Electronics\Models\Electronics; use Database\Factories\Electronics\ElectronicsFactory; use Tests\TestCase; final class ElectronicsTest extends TestCase { use \Illuminate\Foundation\Testing\DatabaseTransactions; public function test_can_create_electronics(): void { $item = ElectronicsFactory::new()->create(['tenant_id' => 1]); $this->assertDatabaseHas('electronics', ['id' => $item->id]); } public function test_premium_electronics(): void { $item = ElectronicsFactory::new()->premium()->create(['tenant_id' => 1]); $this->assertGreaterThanOrEqual(500000, $item->price); } public function test_budget_electronics(): void { $item = ElectronicsFactory::new()->budget()->create(['tenant_id' => 1]); $this->assertLessThanOrEqual(250000, $item->price); } public function test_category(): void { $item = ElectronicsFactory::new()->create(['tenant_id' => 1, 'category' => 'smartphone']); $this->assertEquals('smartphone', $item->category); } public function test_warranty(): void { $item = ElectronicsFactory::new()->premium()->create(['tenant_id' => 1]); $this->assertEquals(24, $item->warranty_months); } public function test_brand(): void { $item = ElectronicsFactory::new()->create(['tenant_id' => 1]); $this->assertNotEmpty($item->brand); } }
